import React, { useEffect, useState, useRef } from 'react';
import { Play, Pause, RotateCcw } from 'lucide-react';

interface TimerProps {
  durationMinutes: number;
}

const Timer: React.FC<TimerProps> = ({ durationMinutes }) => {
  const totalSeconds = durationMinutes * 60;
  const [timeLeft, setTimeLeft] = useState(totalSeconds);
  const [isActive, setIsActive] = useState(false);
  const intervalRef = useRef<number | null>(null);

  useEffect(() => {
    setTimeLeft(totalSeconds);
    setIsActive(false);
    if (intervalRef.current) window.clearInterval(intervalRef.current);
  }, [durationMinutes, totalSeconds]);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft((prev) => Math.max(0, prev - 1));
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      if (intervalRef.current) window.clearInterval(intervalRef.current);
    }

    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current);
    };
  }, [isActive, timeLeft]);

  const toggleTimer = () => setIsActive(!isActive);
  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(totalSeconds);
  };

  // Format time
  const minutes = Math.floor(timeLeft / 60);
  const seconds = timeLeft % 60;
  const formattedTime = `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;

  // Progress Ring Calculation
  const radius = 120;
  const circumference = 2 * Math.PI * radius;
  const progress = timeLeft / totalSeconds;
  const dashOffset = circumference - progress * circumference;

  // State checks
  const isLowTime = timeLeft <= 300; // 5 minutes
  const timerColor = isLowTime ? '#953420' : '#556bbd';
  const ringColorClass = isLowTime ? 'stroke-meis-red drop-shadow-[0_0_10px_rgba(149,52,32,0.5)]' : 'stroke-meis-blue drop-shadow-[0_0_15px_rgba(85,107,189,0.3)]';

  return (
    <div className="flex flex-col items-center justify-center h-full relative group">
      <div className="relative">
        {/* SVG Ring */}
        <svg width="320" height="320" className="transform -rotate-90">
          {/* Background Circle */}
          <circle
            cx="160"
            cy="160"
            r={radius}
            stroke="#eef5e1"
            strokeWidth="16"
            fill="transparent"
          />
          {/* Progress Circle */}
          <circle
            cx="160"
            cy="160"
            r={radius}
            stroke="currentColor"
            strokeWidth="16"
            fill="transparent"
            strokeDasharray={circumference}
            strokeDashoffset={dashOffset}
            strokeLinecap="round"
            className={`transition-all duration-1000 ease-linear ${ringColorClass}`}
          />
        </svg>

        {/* Inner Content */}
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className={`text-xl font-bold mb-1 uppercase tracking-widest ${isLowTime ? 'text-meis-red' : 'text-meis-blue'}`}>
            Exam Timer
          </span>
          <span className={`text-7xl font-mono font-bold tracking-tighter ${isLowTime ? 'text-meis-red' : 'text-gray-800'}`}>
            {formattedTime}
          </span>
          <span className="text-sm text-gray-400 font-medium mt-2">
            {isActive ? 'Running' : 'Paused'}
          </span>
        </div>
      </div>

      {/* Controls (Visible on Hover for cleanliness in classroom) */}
      <div className="absolute bottom-[-20px] opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex gap-4 bg-white/80 backdrop-blur-md p-2 rounded-full shadow-lg border border-meis-blue/20">
        <button
          onClick={toggleTimer}
          className="p-3 rounded-full hover:bg-meis-blue hover:text-white text-meis-blue transition-colors"
        >
          {isActive ? <Pause size={20} /> : <Play size={20} />}
        </button>
        <button
          onClick={resetTimer}
          className="p-3 rounded-full hover:bg-meis-red hover:text-white text-meis-red transition-colors"
        >
          <RotateCcw size={20} />
        </button>
      </div>
    </div>
  );
};

export default Timer;

