import React from 'react';
import { INSTRUCTIONS } from '../constants';

const Instructions: React.FC = () => {
  // Helper to highlight keywords
  const processText = (text: string) => {
    const parts = text.split(/(\{.*?\})/g);
    return parts.map((part, index) => {
      if (part.startsWith('{') && part.endsWith('}')) {
        return (
          <span key={index} className="text-meis-red font-bold">
            {part.slice(1, -1)}
          </span>
        );
      }
      return part;
    });
  };

  return (
    <div className="glass-panel rounded-2xl p-6 h-full flex flex-col border border-white/60 shadow-lg">
      <h3 className="text-xl font-bold text-meis-blue mb-4 pb-2 border-b border-meis-blue/20 flex items-center">
        <span className="w-2 h-8 bg-meis-blue rounded-full mr-3"></span>
        Students Exam Instructions
      </h3>

      <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
        <ol className="list-decimal list-outside ml-6 space-y-3">
          {INSTRUCTIONS.map((inst, idx) => (
            <li key={idx} className="text-lg text-gray-700 pl-2 marker:text-meis-blue marker:font-bold">
              {processText(inst)}
            </li>
          ))}
        </ol>
      </div>
    </div>
  );
};

export default Instructions;

import React, { useState } from 'react';
import { X, Plus, Trash2, Save } from 'lucide-react';
import { AppState, ClassInfo } from '../types';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentState: AppState;
  onSave: (newState: AppState) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, currentState, onSave }) => {
  const [formData, setFormData] = useState<AppState>(currentState);

  if (!isOpen) return null;

  const handleClassChange = (index: number, field: keyof ClassInfo, value: any) => {
    const newClasses = [...formData.classes];
    newClasses[index] = { ...newClasses[index], [field]: value };
    setFormData({ ...formData, classes: newClasses });
  };

  const addClass = () => {
    setFormData({
      ...formData,
      classes: [
        ...formData.classes,
        { id: Date.now().toString(), name: 'New Class', subject: 'Subject', durationMinutes: 60 }
      ]
    });
  };

  const removeClass = (index: number) => {
    const newClasses = formData.classes.filter((_, i) => i !== index);
    setFormData({ ...formData, classes: newClasses });
  };

  const handleSave = () => {
    onSave(formData);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm">
      <div className="bg-white rounded-3xl w-full max-w-2xl p-8 shadow-2xl animate-scale-up">
        <div className="flex justify-between items-center mb-6 border-b border-gray-100 pb-4">
          <h2 className="text-2xl font-bold text-meis-blue">Dashboard Settings</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full text-gray-500 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-4">
          {/* General Settings */}
          <div className="space-y-4">
            <label className="block">
              <span className="text-sm font-semibold text-gray-600 uppercase tracking-wide">Exam Title</span>
              <input
                type="text"
                value={formData.examTitle}
                onChange={(e) => setFormData({ ...formData, examTitle: e.target.value })}
                className="mt-1 block w-full px-4 py-3 rounded-xl border border-gray-300 focus:border-meis-blue focus:ring focus:ring-meis-blue/20 outline-none transition-all"
              />
            </label>

            <label className="block">
               <span className="text-sm font-semibold text-gray-600 uppercase tracking-wide">Timer Duration (Minutes)</span>
               <input
                 type="number"
                 value={formData.timerDurationMinutes}
                 onChange={(e) => setFormData({ ...formData, timerDurationMinutes: parseInt(e.target.value) || 0 })}
                 className="mt-1 block w-full px-4 py-3 rounded-xl border border-gray-300 focus:border-meis-blue focus:ring focus:ring-meis-blue/20 outline-none transition-all"
               />
            </label>
          </div>

          {/* Class List */}
          <div>
            <div className="flex justify-between items-center mb-3">
              <span className="text-sm font-semibold text-gray-600 uppercase tracking-wide">Classes</span>
              <button
                onClick={addClass}
                className="flex items-center text-sm text-meis-blue font-bold hover:bg-meis-blue/10 px-3 py-1 rounded-lg transition-colors"
              >
                <Plus size={16} className="mr-1" /> Add Class
              </button>
            </div>

            <div className="space-y-3">
              {formData.classes.map((cls, idx) => (
                <div key={cls.id} className="flex gap-3 items-center bg-gray-50 p-3 rounded-xl border border-gray-100">
                  <input
                    type="text"
                    value={cls.name}
                    onChange={(e) => handleClassChange(idx, 'name', e.target.value)}
                    className="flex-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:border-meis-blue outline-none"
                    placeholder="Class Name"
                  />
                  <input
                    type="text"
                    value={cls.subject}
                    onChange={(e) => handleClassChange(idx, 'subject', e.target.value)}
                    className="flex-1 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:border-meis-blue outline-none"
                    placeholder="Subject"
                  />
                   <input
                    type="number"
                    value={cls.durationMinutes}
                    onChange={(e) => handleClassChange(idx, 'durationMinutes', parseInt(e.target.value))}
                    className="w-24 px-3 py-2 rounded-lg border border-gray-200 text-sm focus:border-meis-blue outline-none"
                    placeholder="Mins"
                  />
                  <button onClick={() => removeClass(idx)} className="text-meis-red hover:bg-meis-red/10 p-2 rounded-lg transition-colors">
                    <Trash2 size={18} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-8 pt-4 border-t border-gray-100 flex justify-end">
          <button
            onClick={handleSave}
            className="flex items-center px-8 py-3 bg-gradient-to-r from-meis-blue to-meis-blueLight text-white rounded-xl shadow-lg hover:shadow-xl hover:scale-105 transition-all font-semibold"
          >
            <Save size={20} className="mr-2" />
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
};

export default SettingsModal;

