      case 'blue':
        return <BlueTheme />;
      case 'fuchsia':
        return <FuchsiaTheme />;
      default:
        return <OceanTheme />; // Fallback
    }
  };

  return (
    <div className={containerStyle} aria-hidden="true">
      {renderContent()}
    </div>
  );
};

