          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-border 12s linear infinite;
        }
      `}</style>

      {/* Background Animation Layer */}
      <ThemeBackground theme={appState.theme} />

      {/* Content Layer (z-10 to stay above background) */}
