            <Header examTitle={appState.examTitle} />
        </div>

        {/* Dua Banner */}
        <div className="w-full px-8 shrink-0 mb-4 pointer-events-auto">
          <DuaBanner />
        </div>

        {/* Main Content: 2-Column Grid */}
