import React from 'react';

interface ThemeBackgroundProps {
  theme: string;
}

const ThemeBackground: React.FC<ThemeBackgroundProps> = ({ theme }) => {
  const containerStyle = "absolute inset-0 overflow-hidden pointer-events-none select-none z-0";

  const renderContent = () => {
    switch (theme) {
      case 'ocean':
        return <OceanTheme />;
      case 'emerald':
        return <EmeraldTheme />;
      case 'royal':
        return <RoyalTheme />;
      case 'lavender':
        return <LavenderTheme />;
      case 'rose':
        return <RoseTheme />;
      case 'amber':
        return <AmberTheme />;
      case 'teal':
        return <TealTheme />;
      case 'blue':
        return <BlueTheme />;
      case 'fuchsia':
        return <FuchsiaTheme />;
      default:
        return <OceanTheme />; // Fallback
    }
  };

  return (
    <div className={containerStyle} aria-hidden="true">
      {renderContent()}
    </div>
  );
};

